#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
==============================================================================
  GENERADOR LOCAL DEL PROYECTO  ::  Movimiento Koray
  Sistema de Gestion Clinica Mobile-First (React + Vite + Supabase)
==============================================================================

  COMO USAR:
    1. Crea una carpeta vacia y abrela en Visual Studio Code.
    2. Copia este archivo (setup.py) dentro de esa carpeta.
    3. Abre la terminal (menu Terminal > New Terminal) y ejecuta:

          python setup.py

    4. Se crearan automaticamente todas las carpetas y archivos del proyecto.
    5. Luego instala y ejecuta:

          npm install
          cp .env.example .env      (Windows PowerShell:  copy .env.example .env)
          npm run dev

  No requiere librerias externas: solo Python 3 estandar.
==============================================================================
"""
import os, base64

DESTINO = os.path.dirname(os.path.abspath(__file__))

# Cada archivo del proyecto, codificado en base64.
ARCHIVOS = {
"vite.config.js": "",
"tailwind.config.js": "",
"README.md": "",
"index.html": "",
".gitignore": "bm9kZV9tb2R1bGVzCmRpc3QKLmVudgouRFNfU3RvcmUKKi5sb2NhbAo=",
"postcss.config.js": "ZXhwb3J0IGRlZmF1bHQgewogIHBsdWdpbnM6IHsKICAgIHRhaWx3aW5kY3NzOiB7fSwKICAgIGF1dG9wcmVmaXhlcjoge30KICB9Cn0K",
"package.json": "",
".env.example": "",
"src/index.css": "",
"src/App.jsx": "",
"src/main.jsx": "",
"src/components/Logo.jsx": "",
"src/components/ui.jsx": "",
"src/components/Modal.jsx": "",
"src/components/Layout.jsx": "",
"src/components/Splash.jsx": "",
"src/lib/supabase.js": "",
"src/utils/format.js": "",
"src/pages/Servicios.jsx": "",
"src/pages/Pacientes.jsx": "",
"src/pages/Paquetes.jsx": "",
"src/pages/PacienteDetalle.jsx": "",
"src/pages/Agenda.jsx": "",
"src/pages/Caja.jsx": "",
"src/pages/Dashboard.jsx": "",
"src/pages/Login.jsx": "",
"src/context/AuthContext.jsx": "",
"public/img/LEER_AQUI.txt": "",
"supabase/schema.sql": "",
"img/LEER_AQUI.txt": ""
}


def main():
    total = len(ARCHIVOS)
    print("=" * 62)
    print("  Generando proyecto: Movimiento Koray")
    print("=" * 62)
    creados = 0
    for ruta, b64 in ARCHIVOS.items():
        destino = os.path.join(DESTINO, ruta.replace("/", os.sep))
        carpeta = os.path.dirname(destino)
        if carpeta:
            os.makedirs(carpeta, exist_ok=True)
        with open(destino, "wb") as f:
            f.write(base64.b64decode(b64))
        creados += 1
        print("  [{:>2}/{}]  {}".format(creados, total, ruta))
    print("-" * 62)
    print("  Listo: {} archivos creados.".format(creados))
    print("=" * 62)
    print("""
  Siguientes pasos:

    1) npm install
    2) Configura Supabase: pega supabase/schema.sql en el SQL Editor y Run.
    3) cp .env.example .env   (Windows: copy .env.example .env)
       y coloca VITE_SUPABASE_URL / VITE_SUPABASE_ANON_KEY
    4) Coloca tu logo en  public/img/logo.jpeg
    5) npm run dev   (usa la URL "Network" para probar desde el celular)
""")

if __name__ == "__main__":
    main()
